	Defaults Default `yaml:"second"`
}

func runTest(name, yml, expectedFirst, expectedKey string) bool {
	test := Test{Defaults: Default{Key: "My default Value"}}
	d := yaml.NewDecoder(strings.NewReader(yml))
	if err := d.Decode(&test); err != nil {
		fmt.Printf("❌ %s: Decode error: %v\n", name, err)
		return false
	}

	if test.First != expectedFirst || test.Defaults.Key != expectedKey {
		fmt.Printf("❌ %s: Expected First=%q Key=%q, got First=%q Key=%q\n",
			name, expectedFirst, expectedKey, test.First, test.Defaults.Key)
		return false
	}
	fmt.Printf("✅ %s\n", name)
	return true
}

